INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Sexto Grado', 'Formación Ciudadana', '1. Participa en relaciones sociales que inciden en los derechos y responsabilidades necesarias para una cultura de paz en el contexto nacional e internacional.', ARRAY['1.1. Expresa solidaridad en el espacio escolar, en la familia y la comunidad.', '1.2. Defiende los Derechos Humanos relacionados con el bienestar de las personas y en favor del desarrollo social.', '1.3. Identifica las relaciones sociales de calidad en contextos de diversidad.']),
('Sexto Grado', 'Formación Ciudadana', '2. Fomenta actitudes y acciones orientadas a erradicar la discriminación y exclusión para fortalecer la solidaridad y las culturas de los pueblos.', ARRAY['2.1. Identifica en los acuerdos de paz, las recomendaciones orientadas a erradicar la exclusión y discriminación de la mujer y de los pueblos indígenas.', '2.2. Describe las causas socioeconómicas, culturales y políticas de las asimetrías y la desigualdad.', '2.3. Describe los beneficios de la equidad, tolerancia y cooperación en una sociedad democrática.', '2.4. Identifica los artículos constitucionales que garantizan sus derechos y obligaciones, así como el funcionamiento de las entidades del Estado.', '2.5. Emite juicios acerca de falacias y estereotipos orientados a desarrollar sentimientos de intolerancia, de culpa e inferioridad.']),
('Sexto Grado', 'Formación Ciudadana', '3. Formula proyectos y realizaciones orientadas a favor del ejercicio de la ciudadanía y la democracia en la familia, la comunidad y el país.', ARRAY['3.1. Describe las características del liderazgo y la gestión democrática y autoritaria.', '3.2. Participa democrática y propositivamente en el gobierno estudiantil y la organización del aula.', '3.3. Describe la diversidad de acciones con las que se ejerce ciudadanía.', '3.4. Describe el papel y nivel de desempeño de las instituciones del sistema democrático.', '3.5. Explica el funcionamiento de las instituciones democráticas: del Estado y de la sociedad civil.', '3.6. Describe los derechos y las responsabilidades sociales que tienen los ciudadanos con su persona, su familia, con las instituciones sociales y el país.']),
('Sexto Grado', 'Formación Ciudadana', '4. Promueve acciones para fortalecer la existencia de actitudes y prácticas de cultura de paz en diferentes espacios y situaciones de la vida grupal.', ARRAY['4.1. Valora la ciudadanía cimentada en una cultura de paz.', '4.2. Describe la presencia de la cultura de violencia en su espacio inmediato.', '4.3. Formula propuestas orientadas a transformar y controlar de manera constructiva los conflictos.', '4.4. Identifica los factores sociales y culturales que favorecen la conflictividad y la violencia.', '4.5. Examina el contenido y comenta los propósitos de cada una de las recomendaciones de los informes REMHI y de la CEH.']),
('Sexto Grado', 'Formación Ciudadana', '5. Planifica el futuro personal y comunitario a partir del análisis crítico del pasado y del presente.', ARRAY['5.1. Comenta acerca de los daños ocasionados por las guerras y elabora propuestas para reducir su incidencia.', '5.2. Construye un mapa de los pueblos y departamentos que fueron más afectados por la violencia.']);
